def generate_reference_answer():
    import json
    from mcp_client import call_tool
    from datetime import datetime, timedelta

    execution_log = []
    today = datetime.now()
    end_date = today.strftime('%Y-%m-%d')
    start_date = (today - timedelta(days=30)).strftime('%Y-%m-%d')

    tech_stocks = {"AAPL": "Apple Inc", "MSFT": "Microsoft Corp", "GOOGL": "Alphabet Inc (Google)"}
    all_stocks_rsi_data = {}

    execution_log.append(f"Step 1 & 2: Retrieving historical price data and calculating 14-day RSI for {', '.join(tech_stocks.keys())} for the last 30 days.")
    for symbol, name in tech_stocks.items():
        # Step 1: Get historical price data (noisy output)
        execution_log.append(f"Calling twelvedata_GetTimeSeries for {symbol} from {start_date} to {end_date}")
        raw_time_series = call_tool(
            'twelvedata_GetTimeSeries',
            {
                'params': {
                    'symbol': symbol,
                    'interval': '1day',
                    'start_date': start_date,
                    'end_date': end_date,
                    'outputsize': 30
                }
            }
        )
        execution_log.append(f"[RAW] {str(raw_time_series)[:200]}...")
        time_series_data = json.loads(raw_time_series) if isinstance(raw_time_series, str) else raw_time_series
        # Noisy output: time_series_data['values'] can contain up to 30 items, each with multiple fields
        execution_log.append(f"Retrieved {len(time_series_data.get('values', []))} historical data points for {symbol}.")

        # Step 2: Calculate 14-day RSI (noisy output)
        execution_log.append(f"Calling twelvedata_GetTimeSeriesRsi for {symbol}")
        raw_rsi_series = call_tool(
            'twelvedata_GetTimeSeriesRsi',
            {
                'params': {
                    'symbol': symbol,
                    'interval': '1day',
                    'time_period': 14,
                    'start_date': start_date,
                    'end_date': end_date,
                    'outputsize': 30
                }
            }
        )
        execution_log.append(f"[RAW] {str(raw_rsi_series)[:200]}...")
        rsi_data = json.loads(raw_rsi_series) if isinstance(raw_rsi_series, str) else raw_rsi_series
        # Noisy output: rsi_data['values'] can contain up to 30 items, each with datetime and rsi
        execution_log.append(f"Retrieved {len(rsi_data.get('values', []))} RSI data points for {symbol}.")

        if rsi_data.get('values') and len(rsi_data['values']) > 0:
            # Extract the most recent RSI value for this stock
            most_recent_rsi_entry = rsi_data['values'][0]
            all_stocks_rsi_data[symbol] = {
                'name': name,
                'rsi': float(most_recent_rsi_entry.get('rsi')),
                'datetime': most_recent_rsi_entry.get('datetime')
            }
        else:
            execution_log.append(f"No RSI data found for {symbol}.")

    # Step 3: Identify the company with the lowest most recent RSI
    execution_log.append("Step 3: Identifying the stock with the lowest most recent RSI.")
    lowest_rsi_symbol = None
    lowest_rsi_value = float('inf')
    lowest_rsi_name = None

    for symbol, data in all_stocks_rsi_data.items():
        if data['rsi'] < lowest_rsi_value:
            lowest_rsi_value = data['rsi']
            lowest_rsi_symbol = symbol
            lowest_rsi_name = data['name']

    if not lowest_rsi_symbol:
        return "Could not identify a primary candidate stock due to missing RSI data."

    execution_log.append(f"Identified primary candidate: {lowest_rsi_name} ({lowest_rsi_symbol}) with most recent RSI of {lowest_rsi_value:.2f}.")

    # Step 4 & 5: Get detailed statistics and extract P/E ratio
    execution_log.append(f"Step 4 & 5: Retrieving detailed statistics for {lowest_rsi_name} and extracting P/E ratio.")
    raw_statistics = call_tool(
        'twelvedata_GetStatistics',
        {
            'params': {
                'symbol': lowest_rsi_symbol
            }
        }
    )
    execution_log.append(f"[RAW] {str(raw_statistics)[:200]}...")
    statistics_data = json.loads(raw_statistics) if isinstance(raw_statistics, str) else raw_statistics
    # Noisy output: statistics_data is a large, nested object

    trailing_pe = statistics_data.get('statistics', {}).get('valuations_metrics', {}).get('trailing_pe')
    if trailing_pe is not None:
        trailing_pe = float(trailing_pe)
        execution_log.append(f"Extracted Trailing P/E ratio for {lowest_rsi_name}: {trailing_pe:.2f}.")
    else:
        execution_log.append(f"Trailing P/E ratio not found for {lowest_rsi_name}.")
        trailing_pe = "N/A"

    # Step 6: Get current real-time price
    execution_log.append(f"Step 6: Retrieving current real-time price for {lowest_rsi_name}.")
    raw_price = call_tool(
        'twelvedata_GetPrice',
        {
            'params': {
                'symbol': lowest_rsi_symbol
            }
        }
    )
    execution_log.append(f"[RAW] {str(raw_price)[:200]}...")
    price_data = json.loads(raw_price) if isinstance(raw_price, str) else raw_price

    current_price = price_data.get('price')
    if current_price is not None:
        current_price = float(current_price)
        execution_log.append(f"Current real-time price for {lowest_rsi_name}: {current_price:.2f}.")
    else:
        execution_log.append(f"Current real-time price not found for {lowest_rsi_name}.")
        current_price = "N/A"

    # Step 7: Final comparison and output
    benchmark_pe = 25.0
    pe_comparison = "N/A"
    if isinstance(trailing_pe, float):
        if trailing_pe > benchmark_pe:
            pe_comparison = "above"
        else:
            pe_comparison = "below"

    final_answer = (
        f"Primary Candidate Stock: {lowest_rsi_name} ({lowest_rsi_symbol})\n"
        f"Most Recent 14-day RSI: {lowest_rsi_value:.2f}\n"
        f"Trailing P/E Ratio: {trailing_pe:.2f} (Industry Benchmark: {benchmark_pe:.1f})\n"
        f"Current Real-time Price: {current_price:.2f}\n"
        f"The Trailing P/E ratio is {pe_comparison} the industry benchmark of {benchmark_pe:.1f}."
    )

    execution_log.append("Final Answer:\n" + final_answer)

    return "\n".join(execution_log)
